CODE_EXAMPLE:
// All statements at the same abstraction level
public void buildPage(Page page) {
    String renderedHtml = renderHtml(page);
    appendToBuffer(renderedHtml);
    includeTeardown(page);
}

private String renderHtml(Page page) { return page.getHtml(); }
private void appendToBuffer(String content) { buffer.append(content); }

UNIT_TEST_EXAMPLE:
@Test
public void buildPage_appendsHtmlAndTeardown() {
    Page page = new Page("<p>content</p>");
    PageBuilder builder = new PageBuilder();
    builder.buildPage(page);
    String result = builder.getBuffer();
    assertTrue(result.contains("<p>content</p>"));
    assertTrue(result.contains("teardown"));
}
